from flask import Flask, request, jsonify
from elasticsearch import Elasticsearch
from flask_limiter import Limiter
from flask_limiter.util import get_remote_address
import time
import logging

app = Flask(__name__)

# Configure Elasticsearch
es = Elasticsearch([{'host': 'localhost', 'port': 9200}])

# Configure rate limiting
limiter = Limiter(
    app,
    key_func=get_remote_address,
    default_limits=["100 per hour"],
    storage_uri="memory://",
)

# Configure logging
logging.basicConfig(level=logging.INFO)
logger = logging.getLogger(__name__)

# In-memory tracking for abuse detection
search_tracker = {}

@app.route('/api/search', methods=['GET'])
@limiter.limit("50 per minute")
def search_products():
    try:
        # Get query parameter
        query = request.args.get('q', '').strip()
        
        # Validate query
        if not query:
            return jsonify({"error": "Query parameter 'q' is required"}), 400
            
        if len(query) > 100:
            return jsonify({"error": "Query too long"}), 400
            
        # Track searches for abuse detection
        client_ip = get_remote_address()
        current_time = time.time()
        
        if client_ip not in search_tracker:
            search_tracker[client_ip] = []
            
        # Remove old entries (older than 1 hour)
        search_tracker[client_ip] = [
            entry for entry in search_tracker[client_ip] 
            if current_time - entry < 3600
        ]
        
        # Check if too many searches in last hour
        if len(search_tracker[client_ip]) > 1000:
            logger.warning(f"Abuse detected for IP: {client_ip}")
            return jsonify({"error": "Rate limit exceeded"}), 429
            
        search_tracker[client_ip].append(current_time)
        
        # Search in Elasticsearch
        search_body = {
            "query": {
                "multi_match": {
                    "query": query,
                    "type": "bool_prefix",
                    "fields": ["name", "description", "category"]
                }
            },
            "size": 50
        }
        
        response = es.search(index="products", body=search_body)
        
        # Format results
        results = []
        for hit in response['hits']['hits']:
            source = hit['_source']
            results.append({
                'id': source.get('id'),
                'name': source.get('name'),
                'description': source.get('description'),
                'price': source.get('price'),
                'category': source.get('category')
            })
            
        return jsonify({
            "query": query,
            "count": len(results),
            "results": results
        })
        
    except Exception as e:
        logger.error(f"Search error: {str(e)}")
        return jsonify({"error": "Internal server error"}), 500

# Health check endpoint
@app.route('/health', methods=['GET'])
def health_check():
    return jsonify({"status": "healthy"})

if __name__ == '__main__':
    app.run(debug=False, host='0.0.0.0', port=5000)